import crypto from "crypto";
import path from "path";

import fs from "fs-extra";

import type { DatabaseConfig, EnvGenerationResult } from "../types";

/**
 * Generate a cryptographically secure NEXTLY_SECRET.
 */
function generateNextlySecret(): string {
  return crypto.randomBytes(32).toString("base64");
}

/**
 * Generate the environment file template.
 */
function getEnvTemplate(database: DatabaseConfig): string {
  return `# Nextly Configuration
# Generated by create-nextly-app

# Database Configuration
DB_DIALECT=${database.type}
DATABASE_URL=${database.envExample}

# Authentication (auto-generated, change if needed)
NEXTLY_SECRET=${generateNextlySecret()}

# Application URL
NEXT_PUBLIC_APP_URL=http://localhost:3000
`;
}

/**
 * Generate or update the .env file with Nextly configuration.
 *
 * @param cwd - Working directory
 * @param database - Database configuration
 */
export async function generateEnv(
  cwd: string,
  database: DatabaseConfig
): Promise<EnvGenerationResult> {
  const envPath = path.join(cwd, ".env");
  const envExamplePath = path.join(cwd, ".env.example");

  const envContent = getEnvTemplate(database);

  // Always create/update .env.example
  await fs.writeFile(envExamplePath, envContent, "utf-8");

  // Check if .env exists
  if (await fs.pathExists(envPath)) {
    // Append Nextly config if not present
    const existingEnv = await fs.readFile(envPath, "utf-8");
    if (!existingEnv.includes("DATABASE_URL")) {
      await fs.appendFile(envPath, "\n" + envContent, "utf-8");
      return { created: false, updated: true };
    }
    return { created: false, updated: false };
  }

  // Create new .env
  await fs.writeFile(envPath, envContent, "utf-8");
  return { created: true, updated: false };
}
